type Location = {
  id: string;
  name: string;
  address: any;
  email: any;
  phone1: string;
  phone2?: string;
  fax?: string;
  color: string;
  iconUrl: string | null;
};

function LocationCard({ location }: { location: Location }) {
  return (
    <div
      className="relative flex flex-col p-5 rounded-3xl bg-white"
      style={{
        border: `3px solid ${location.color}`,
        borderRadius: "24px",
      }}
    >
      {/* Top-right icon */}
      <div className="absolute -top-10 right-4 md:right-5">
        <div
          style={{
            width: 76,
            height: 80,
            borderRadius: 16,
            overflow: "hidden",
            backgroundColor: location.color,
            position: "relative",
          }}
        >
          {location.iconUrl && (
            <Image
              src={location.iconUrl}
              alt={location.name}
              fill
              className="object-cover"
            />
          )}
        </div>
      </div>

      {/* Card title */}
      <h2
        style={{
          fontFamily: "var(--font-family)",
          fontWeight: 500,
          fontSize: "24px",
          lineHeight: "140%",
          color: "#000",
          marginBottom: "16px",
          paddingRight: "80px",
        }}
      >
        {location.name}
      </h2>

      {/* Inner white box */}
      <div
        style={{
          border: "1px solid #e4e4e4",
          borderRadius: "16px",
          padding: "12px 16px",
          background: "#fff",
          marginBottom: "10px",
          flex: 1,
        }}
      >
        {/* Address row */}
        <div className="flex items-start gap-5 mb-3">
          <div className="flex-shrink-0 mt-[2px]">
            <LocationPinSvg />
          </div>
          <div
            style={{
              fontFamily: "var(--font-family)",
              fontWeight: 400,
              fontSize: "15px",
              lineHeight: "160%",
              color: "#111",
            }}
          >
            {location.address}
          </div>
        </div>

        {/* Contacts gray box */}
        <div
          style={{
            background: "#f1f1f1",
            borderRadius: "16px",
            padding: "12px 16px",
          }}
        >
          {location.phone1 && (
            <a
              href={`tel:${location.phone1.replace(/\s/g, "")}`}
              className="flex items-center gap-3 hover:text-[#e84814] mb-3"
              style={{
                fontFamily: "var(--font-family)",
                fontSize: "15px",
                color: "#111",
              }}
            >
              <PhoneSvg />
              {location.phone1}
            </a>
          )}

          {location.email && (
            <div
              className="flex items-center gap-3 mb-3"
              style={{
                fontFamily: "var(--font-family)",
                fontSize: "15px",
                color: "#111",
              }}
            >
              <EmailSvg />
              {location.email}
            </div>
          )}
          {location.fax && (
            <div
              className="flex items-center gap-3 mb-3"
              style={{
                fontFamily: "var(--font-family)",
                fontSize: "15px",
                color: "#111",
              }}
            >
              <FaxSvg />
              {location.fax}
            </div>
          )}

          {location.phone2 && (
            <a
              href={`tel:${location.phone2.replace(/\s/g, "")}`}
              className="flex items-center gap-3 hover:text-[#e84814]"
              style={{
                fontFamily: "var(--font-family)",
                fontSize: "15px",
                color: "#111",
              }}
            >
              <PhoneSvg />
              {location.phone2}
            </a>
          )}
        </div>
      </div>

      <div className="md:flex-row flex-col flex gap-3 mt-[10px]">
        <BlackActionButton
          label="Show on Map"
          className="flex-1 !m-0 md:!w-[50%]"
          icon={
            <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
              <path
                d="M17.5 7.49996H6.25C4.17893 7.49996 2.5 9.17889 2.5 11.25C2.5 13.321 4.17893 15 6.25 15H10M17.5 7.49996L14.1667 4.16663M17.5 7.49996L14.1667 10.8333"
                stroke="#111111"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          }
        />
        <ButtonWithIcon
          label="Find More"
          textColor="text-black"
          className="!w-full md:!w-[50%] bg-[#f1f1f1]!"
          icon={
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="44"
              height="44"
              viewBox="0 0 44 44"
              fill="none"
            >
              <rect width="44" height="44" rx="22" fill="#E84814" />
              <path
                d="M30 20.3333H18.75C16.6789 20.3333 15 22.0123 15 24.0833C15 26.1544 16.6789 27.8333 18.75 27.8333H22.5M30 20.3333L26.6667 17M30 20.3333L26.6667 23.6667"
                stroke="#F1F1F1"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          }
        />
      </div>
    </div>
  );
}
type ApiContact = {
  name: string;
  icon_url: string | null;
  color: string;
  contacts: {
    phone: string;
    email: string;
    fax: string | null;
    address: string;
    tripadvisor: string;
    facebook: string;
    location: { latitude: string; longitude: string };
  };
};

export default function LocationsSection({
  contacts,
}: {
  contacts: ApiContact[];
}) {
  console.log(contacts, "contacts");

  return (
    <section className="bg-[#f1f1f1] px-4 pb-12 pt-8 md:px-[30px] md:pb-[50px] md:pt-[46px]">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-x-8 gap-y-[50px] pt-6">
        {contacts.map((loc) => {
          const phones = loc.contacts.phone.split(", ");
          return (
            <LocationCard
              key={loc.name}
              location={{
                id: loc.name.toLowerCase().replace(" ", "-"),
                name: loc.name,
                address: [loc.contacts.address], // или разбить строку
                phone1: phones[0] ?? "",
                phone2: phones[1] ?? "",
                fax: loc.contacts.fax ?? "",
                email: loc.contacts.email,
                color: loc.color,
                iconUrl: loc.icon_url,
              }}
            />
          );
        })}
      </div>
    </section>
  );
}
